# typed: false
# frozen_string_literal: true

require "json"

# Generated by eng/release/generate-package-manifests.cs. Do not edit by hand.
class HpdosBeta < Formula
  env :std

  desc "Interactive HPD-OS coding TUI powered by HPD-Agent"
  homepage "https://github.com/HPD-AI/HPD-OS"
  version "0.1.0-beta.1"
  url "https://github.com/HPD-AI/homebrew-tap", using: :git, branch: "main"

  depends_on "gh" => :run

  def release_tag
    "hpdos-tui-v#{version}"
  end

  def artifact_name
    if OS.mac?
      Hardware::CPU.arm? ? "hpdos-osx-arm64.tar.gz" : "hpdos-osx-x64.tar.gz"
    elsif OS.linux?
      Hardware::CPU.arm? ? "hpdos-linux-arm64.tar.gz" : "hpdos-linux-x64.tar.gz"
    else
      odie "Unsupported platform for HPDOS release binary."
    end
  end

  def gh_env
    token = ENV["HOMEBREW_GITHUB_API_TOKEN"] || ENV["GITHUB_TOKEN"] || ENV["GH_TOKEN"]
    return {} if token.to_s.strip.empty?

    {
      "GITHUB_TOKEN" => token,
      "GH_TOKEN" => token,
      "HOMEBREW_GITHUB_API_TOKEN" => token,
    }
  end

  def release_json
    output = Utils.safe_popen_read(
      gh_env,
      "gh",
      "release",
      "view",
      release_tag,
      "--repo",
      "HPD-AI/HPD-OS",
      "--json",
      "assets",
    )

    JSON.parse(output)
  rescue ErrorDuringExecution => e
    odie <<~MSG
      Failed to read release #{release_tag} from GitHub. Ensure `gh auth login` succeeds first and retry.
      Details: #{e.message}
    MSG
  rescue JSON::ParserError
    odie "Failed to parse release metadata from GitHub for #{release_tag}."
  end

  def install
    release = release_json
    artifact = release.fetch("assets", []).find { |a| a["name"] == artifact_name }
    odie "Release asset #{artifact_name} not found in #{release_tag}." if artifact.nil?

    downloaded = system(
      gh_env,
      "gh",
      "release",
      "download",
      release_tag,
      "--repo",
      "HPD-AI/HPD-OS",
      "--pattern",
      artifact_name,
      "--clobber",
    )
    odie <<~MSG unless downloaded && File.exist?(artifact_name)
      Failed to download #{artifact_name} from release #{release_tag}.
      Verify that `gh auth login` is complete and this repo is accessible.
      You can test quickly with: gh release download #{release_tag} --repo HPD-AI/HPD-OS --pattern #{artifact_name}
    MSG

    system "tar", "-xzf", artifact_name
    odie "Downloaded archive did not contain expected hpdos binary." unless File.exist?("hpdos")

    bin.install "hpdos"
    bin.install_symlink bin/"hpdos" => "hpdos-beta"
  end

  test do
    assert_match "HPDOS", shell_output("#{bin}/hpdos --help")
  end
end
